const input = $input.first().json;

const veioDoWebhook = !!input.body;

function formatarData(data) {

  if (!data) return '';

  const limpa = data.split('T')[0];

  const [ano, mes, dia] = limpa.split('-');

  return `${dia}/${mes}/${ano}`;
}

// =========================
// Formata endereço ReceitaWS
// =========================
function montarEnderecoReceita(receita) {

  if (!receita) return '';

  const logradouro = receita.logradouro || '';
  const numero = receita.numero || '';
  const complemento = receita.complemento
    ? ' - ' + receita.complemento
    : '';

  const bairro = receita.bairro || '';
  const municipio = receita.municipio || '';

  const uf = (receita.uf || '').toUpperCase();

  const cep = (receita.cep || '')
    .replace(/\D/g, '')
    .replace(/(\d{5})(\d{3})/, '$1-$2');

  const titleCase = (str) =>
    str
      .toLowerCase()
      .replace(/\b[a-zà-ú]/gi, (c) => c.toUpperCase());

  return `${titleCase(logradouro)}, ${numero}${complemento}, ${titleCase(bairro)}, ${titleCase(municipio)}, ${uf}, ${cep}`;
}

// =========================
// Busca endereço via ReceitaWS
// =========================
async function buscarEnderecoPorCNPJ(cnpj) {
  if (!cnpj) {
    return '';
  }

  try {

    const cnpjLimpo = cnpj.replace(/\D/g, '');

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.receitaws.com.br/v1/cnpj/${cnpjLimpo}`,
      json: true
    });

    return montarEnderecoReceita(response);

  } catch (e) {

    return '';
  }
}

// =========================
// Busca cidade/UF via CNPJ
// =========================
async function buscarCidadePorCNPJ(cnpj) {
  if (!cnpj) {
    return '';
  }

  try {

    const cnpjLimpo = cnpj.replace(/\D/g, '');

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.receitaws.com.br/v1/cnpj/${cnpjLimpo}`,
      json: true
    });

    const municipio = response.municipio || '';
    const uf = (response.uf || '').toUpperCase();

    if (!municipio || !uf) {
      return '';
    }

    return `${municipio}/${uf}`;

  } catch (e) {

    return '';
  }
}

// =========================
// Busca cidade/UF via endereço
// =========================
async function buscarCidadePorEndereco(endereco) {

  if (!endereco) {
    return '';
  }

  try {

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nominatim.openstreetmap.org/search',
      qs: {
        q: endereco,
        format: 'jsonv2',
        limit: 1,
        addressdetails: 1
      },
      headers: {
        'User-Agent': 'n8n'
      },
      json: true
    });

    if (!response.length) {
      return '';
    }

    const address = response[0].address || {};

    const cidade =
      address.city ||
      address.town ||
      address.village ||
      address.municipality ||
      '';

    const uf =
      address.state_code ||
      address.state ||
      '';

    if (!cidade) {
      return '';
    }

    return uf ? `${cidade}/${uf}` : cidade;

  } catch (e) {

    return '';
  }
}

function gerarDataSubmissao() {

  const meses = [
    'Janeiro',
    'Fevereiro',
    'Março',
    'Abril',
    'Maio',
    'Junho',
    'Julho',
    'Agosto',
    'Setembro',
    'Outubro',
    'Novembro',
    'Dezembro'
  ];

  const hoje = new Date();

  const dia = hoje.getDate();
  const mes = meses[hoje.getMonth()];
  const ano = hoje.getFullYear();

  return `${dia} de ${mes} de ${ano}`;
}

function obterPrazo(tipo, dias) {

  switch (tipo) {

    case 'sem_prazo':
      return '';

    case 'imediato':
      return 'Imediato';

    case 'dias':
      return dias ? String(dias) : '';

    default:
      return '';
  }
}

function formatarPercentual(valor) {

  if (
    valor === null ||
    valor === undefined ||
    valor === ''
  ) {
    return '';
  }

  return `${valor}%`;
}

function formatarMoeda(valor) {

  if (
    valor === null ||
    valor === undefined ||
    valor === ''
  ) {
    return '';
  }

  return Number(valor).toLocaleString(
    'pt-BR',
    {
      style: 'currency',
      currency: 'BRL'
    }
  );
}

