  // =========================
  // WEBHOOK / PLATAFORMA
  // =========================

  const body = input.body;

  const placeholders = body.placeholders || {};

  const prazo = obterPrazo(
    placeholders.prazo_tipo,
    placeholders.prazo_dias
  );

  let endereco = placeholders.endereco_condominio || '';

  let cidade = '';

  // Busca via CNPJ se endereço vazio
  if (!endereco && placeholders.numero_cnpj) {

    endereco = await buscarEnderecoPorCNPJ.call(
      this,
      placeholders.numero_cnpj
    );
  }
  if (placeholders.numero_cnpj) {

    cidade = await buscarCidadePorCNPJ.call(
      this,
      placeholders.numero_cnpj
    );

  } else if (endereco) {

    cidade = await buscarCidadePorEndereco.call(
      this,
      endereco
    );
  }

  const percentualTaxa = formatarPercentual(
    body.percentual_taxa
  );

  const valorAdicional = formatarMoeda(
    body.valor_adicional
  );

  const valorTaxa = formatarMoeda(
    body.valor_taxa
  );

  const descricaoValorAdicional =
    body.descricao_valor_adicional || '';

  output = {

    origem: 'Plataforma',

    cidade: cidade,

    data_submissao: dataSubmissao,

    prazo: prazo,

    percentual_taxa: percentualTaxa,

    valor_adicional: valorAdicional,

    valor_taxa: valorTaxa,

    descricao_valor_adicional:
