  if (!endereco && dadosCadastro.condominio_cnpj) {
    endereco = await buscarEnderecoPorCNPJ.call(
      this,
      dadosCadastro.condominio_cnpj
    );
  }

  if (dadosCadastro.condominio_cnpj) {

    cidade = await buscarCidadePorCNPJ.call(
      this,
      dadosCadastro.condominio_cnpj
    );

  } else if (endereco) {

    cidade = await buscarCidadePorEndereco.call(
      this,
      endereco
    );
  }

  const percentualTaxa = formatarPercentual(
  dadosMulta.percentual_taxa
);

  const valorAdicional = formatarMoeda(
  dadosMulta.valor_adicional
);

  const valorTaxa = formatarMoeda(
  dadosMulta.valor_taxa
);

  const descricaoValorAdicional =
  dadosMulta.descricao_valor_adicional || '';

  output = {

  origem: 'N8N',

  cidade: cidade,

  data_submissao: dataSubmissao,

  prazo: prazo,

  percentual_taxa: percentualTaxa,

  valor_adicional: valorAdicional,

  valor_taxa: valorTaxa,

  descricao_valor_adicional:
    descricaoValorAdicional,

  id_condomino:
    dadosCadastro.condomino_id || '',

  numero_bloco:
    dadosMulta.bloco || '',

  numero_unidade:
    dadosMulta.unidade || '',

  data_infracao: formatarData(
    dadosMulta.data_infracao
  ),

  foto_infracao:
    dadosMulta.foto_infracao_path || '',

  foto_infracao_2:
    dadosMulta.foto_infracao_path_2 || '',

  id_condominio:
    dadosCadastro.condominio_id || '',

  nome_condominio:
    dadosCadastro.condominio_nome || '',

  numero_cnpj:
    dadosCadastro.condominio_cnpj || '',

  nome_sindico:
    dadosCadastro.condominio_sindico_nome
      ? `${dadosCadastro.condominio_sindico_nome} - síndico`
      : '',

  assinatura_sindico:
    dadosCadastro.condominio_sindico_assinatura || null,

  logo_condominio:
    dadosCadastro.condominio_logo_url || '',

  endereco_condominio:
    endereco,

  infracao:
    dadosMulta.infracao || '',

  template_corpo:
    '1hfVVQu4TX9RxW_Hs9aICY5gPATQBFneg3R3u_XvH1X4'
};
}
return [
  {
    json: output
  }
];

