return items.map(item => {

  let data = item.json.query;

  // Converte string JSON para objeto
  if (typeof data === 'string') {
    try {
      data = JSON.parse(data);
    } catch (error) {
      throw new Error(
        `Campo query contém JSON inválido: ${error.message}`
      );
    }
  }

  // =====================
  // Obrigatórios
  // =====================

  const obrigatorios = [
    'condominio_id',
    'bloco',
    'unidade',
    'botPhoneNumber',
    'data_infracao',
    'infracao'
  ];

  for (const campo of obrigatorios) {

    if (
      data[campo] === undefined ||
      data[campo] === null ||
      String(data[campo]).trim() === ''
    ) {
      throw new Error(
        `Campo obrigatório "${campo}" não informado.`
      );
    }
  }

  // =====================
  // Data YYYY-MM-DD
  // =====================

  const dataRegex =
    /^\d{4}-\d{2}-\d{2}$/;

  if (!dataRegex.test(data.data_infracao)) {
    throw new Error(
      'data_infracao deve estar no formato YYYY-MM-DD.'
    );
  }

  // =====================
  // Valor da multa
  // =====================

  const possuiValor =
    data.valor_taxa !== undefined ||
    data.percentual_taxa !== undefined ||
    data.valor_adicional !== undefined;

  if (!possuiValor) {
    throw new Error(
      'Informe pelo menos um entre valor_taxa, percentual_taxa ou valor_adicional.'
    );
  }

  // =====================
  // Valor adicional
  // =====================

  if (
    data.valor_adicional !== undefined &&
    (
      !data.descricao_valor_adicional ||
      String(data.descricao_valor_adicional).trim() === ''
    )
  ) {
    throw new Error(
      'descricao_valor_adicional é obrigatória quando valor_adicional for informado.'
    );
  }

  // =====================
  // Prazo
  // =====================

  const tiposPrazoPermitidos = [
    'imediato',
    'dias',
    'sem_prazo'
  ];

  if (
    data.prazo_tipo &&
    !tiposPrazoPermitidos.includes(data.prazo_tipo)
  ) {
    throw new Error(
      'prazo_tipo deve ser "imediato", "dias" ou "sem_prazo".'
    );
  }

  if (
    data.prazo_tipo === 'dias' &&
    (
      data.prazo_dias === undefined ||
      data.prazo_dias === null ||
      data.prazo_dias === ''
    )
  ) {
    throw new Error(
      'prazo_dias é obrigatório quando prazo_tipo = "dias".'
    );
  }

  return {
    json: data
  };
});

